<?php require_once __DIR__.'/../../backend/shared/auth.php'; require_role('doctor'); require_once __DIR__.'/../../backend/shared/layout.php'; $hn=$_GET['hn']??''; $st=db()->prepare('SELECT * FROM patients WHERE hn=?');$st->execute([$hn]);$p=$st->fetch(); $v=db()->prepare('SELECT * FROM visits WHERE patient_id=? ORDER BY visit_date DESC,id DESC');$v->execute([$p['id']]);$visits=$v->fetchAll(); app_header('Timeline ทั้งหมด '.$p['hn'],'doctor','dashboard');?><a class="back" href="patient-profile.php?hn=<?=urlencode($p['hn'])?>">← กลับข้อมูลผู้ป่วย</a><div class="card"><h3>Timeline ทั้งหมด</h3><div class="timeline"><?php foreach($visits as $vv):?><div class="tl-item"><div class="tl-head"><div><div class="tl-title"><?=e($vv['visit_date'])?> · <?=e($vv['visit_type'])?> · <?=e($vv['department'])?></div><div class="tl-meta"><?=e($vv['hospital_name'])?> · <?=e($vv['ward'])?> · <?=e($vv['doctor_name'])?></div></div><a class="btn secondary" href="visit-detail.php?id=<?=$vv['id']?>">ดูรายละเอียด</a></div><p><?=e($vv['chief_complaint'])?></p></div><?php endforeach;?></div></div><?php app_footer();?>
